sqlMap.insert:
insert into tbl_journal_form_type (
	type_id, 	company_id, 	tenant_id
) values (
	#typeId#,	#companyId#,	#tenantId#
)

insert into tbl_journal_form_use_dept (
	dept_id, 	form_id, 	tenant_id
) values (
	#deptId#, 	#formId#, 	#tenantId#
)

insert into tbl_journal_recv_favorite (
	favorite_id,								tenant_id, 	user_id, 	favorite_name, 	favorite_date
) values (
	SEQ_TBL_JOURNAL_RECV_FAVORITE.NEXTVAL,		#tenantId#, #userId#, 	#favoriteName#, TO_DATE(#nowDate#, 'YYYY-MM-DD HH24:MI:SS')
)

	SELECT max(favorite_id) from tbl_journal_recv_favorite

insert into tbl_journal_recv_favorite_list (
	favorite_id, 	user_id, 	tenant_id
) values (
	#favoriteId#, 	#userId#, 	#tenantId#
)

insert into tbl_journal ( journal_id, tenant_id, journal_title, journal_content, journal_date, journal_writer, form_id, dept_share, journal_dept, journal_text, journal_sum
, journal_status
) values ( SEQ_TBL_JOURNAL.NEXTVAL, #tenantId#, #title#, #content#, TO_DATE(#writeDate#, 'YYYY-MM-DD HH24:MI:SS'), #writerId#, #formId#, #deptShare#, #deptId#, #journalText#, #isSum#
, #journalStatus#
)
SELECT max(journal_id) from tbl_journal

insert into tbl_journal_file (
	file_id,						journal_id, 	file_path, 		file_size, 		file_name, 		tenant_id
) values (
	SEQ_TBL_JOURNAL_FILE.NEXTVAL,	#journalId#, 	#filePath#, 	#fileSize#, 	#fileName#, 	#tenantId#
)

insert into tbl_journal_recv (
	journal_id, 	user_id, 		tenant_id
) values (
	#journalId#, 	#receiverId#, 	#tenantId#
)

sqlMap.select:
SELECT * FROM (SELECT AAA.*, rownum as rNum from (
select b.user_id as user_id, a.DISPLAYNAME$lang$ as user_name, a.DESCRIPTION$lang$ as dept_name, a.TITLE$lang$ as jikwi, nvl(TO_CHAR(b.recieve_date + #offset# / (24 * 60), 'YYYY-MM-DD HH24:MI:SS'), '-') as receive_date from tbl_usermaster a join tbl_journal_recv b on (a.CN = b.user_id and a.TENANT_ID = b.tenant_id) where b.journal_id = #journalId# and a.tenant_id = #tenantId# and b.user_id in (select CN from tbl_usermaster) order by lpad(nvl(a.EXTENSIONATTRIBUTE15, 0), 6, 0), a.DISPLAYNAME$lang$
)AAA where rownum <= (#startCount# + #listCnt#) ) where rNum >= (#startCount# + 1)
